INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'outpatient-vs-inpatient', '통원과 입원의 차이 — 실손 보장 한도가 갈리는 기준', '실손보험에서 통원과 입원이 보장 한도·자기부담에서 어떻게 다른지, 애매한 경우(낮병동·당일 처치)의 판단 기준을 정리했습니다.', '<p>실손보험은 통원과 입원을 구분해 보장 한도와 자기부담을 다르게 적용합니다. 같은 진료라도 어떻게 분류되느냐에 따라 받는 금액이 달라질 수 있습니다.</p>
<h2>통원과 입원의 구분</h2>
<ul>
<li>통원: 외래 진료, 보통 1일 한도가 정해져 있음</li>
<li>입원: 일정 시간 이상 병상에서 치료, 연간 한도 안에서 보장</li>
</ul>
<h2>애매한 경우</h2>
<p>당일 입·퇴원, 낮병동 치료 등은 통원인지 입원인지 다툼이 생길 수 있습니다. 일반적으로 입원실 사용과 치료 시간, 의학적 필요성 등을 종합해 판단합니다.</p>
<table>
<thead><tr><th>구분</th><th>한도 성격</th></tr></thead>
<tbody>
<tr><td>통원</td><td>1일·1회 한도</td></tr>
<tr><td>입원</td><td>연간 통합 한도</td></tr>
</tbody>
</table>
<p>입원으로 인정되면 한도가 커지는 경우가 많아, 입·퇴원확인서에 입원 여부가 명확히 적히도록 하는 것이 유리합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>통원=1일 한도, 입원=연간 한도</li><li>낮병동 등은 분류 다툼 가능</li><li>입원 여부 서류에 명확히</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","통원","입원"]', '[{"q":"당일 입퇴원도 입원인가요?","a":"입원실 사용·치료 시간·의학적 필요성을 종합해 판단합니다. 입퇴원확인서의 기재가 중요합니다."},{"q":"통원 한도를 넘으면 어떻게 되나요?","a":"1일 한도를 넘는 부분은 보장되지 않을 수 있습니다. 한도는 세대·상품마다 다릅니다."},{"q":"입원이 통원보다 유리한가요?","a":"연간 통합 한도가 적용돼 큰 치료비에 유리한 경우가 많지만, 분류는 의학적 사실에 따릅니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'claim-dispute-fss-complaint', '보험금 분쟁 대응 — 금융감독원 민원 활용법', '보험금 지급이 거절·지연되거나 과실비율에 이견이 있을 때 활용할 수 있는 금융감독원 민원과 분쟁조정 절차를 정리했습니다.', '<p>보험금이 부당하게 거절·지연되었다고 느낄 때, 무작정 포기하거나 소송으로 가기 전에 활용할 수 있는 제도가 있습니다.</p>
<h2>1차: 보험사에 정식 이의</h2>
<ul>
<li>거절 사유를 서면으로 받기</li>
<li>약관 근거를 확인하고 반박 자료(진단서·소견서) 보강</li>
</ul>
<h2>2차: 금융감독원 민원·분쟁조정</h2>
<p>보험사와 해결이 안 되면 금융감독원에 민원을 제기하거나 금융분쟁조정을 신청할 수 있습니다. 조정은 소송보다 부담이 적고 무료로 진행됩니다.</p>
<table>
<thead><tr><th>단계</th><th>특징</th></tr></thead>
<tbody>
<tr><td>보험사 이의</td><td>서면 근거 확보</td></tr>
<tr><td>금감원 민원</td><td>중립적 검토</td></tr>
<tr><td>분쟁조정</td><td>조정안 제시</td></tr>
<tr><td>소송</td><td>최종 수단</td></tr>
</tbody>
</table>
<p>핵심은 객관적 의료 자료입니다. 거절 사유에 맞춘 소견서나 추가 검사 결과가 결정적 역할을 합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>거절 사유를 서면으로 확보</li><li>금감원 민원·분쟁조정은 무료</li><li>객관적 의료 자료가 관건</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","분쟁조정","금융감독원"]', '[{"q":"금융감독원 민원은 어떻게 내나요?","a":"금융감독원 민원 창구(전화·온라인)를 통해 접수할 수 있습니다. 거절 통지서와 의료 자료를 함께 준비하세요."},{"q":"분쟁조정은 강제력이 있나요?","a":"조정안 수락 시 효력이 있습니다. 양측이 수락하지 않으면 소송으로 갈 수 있습니다."},{"q":"비용이 드나요?","a":"금감원 민원과 분쟁조정은 무료입니다. 소송은 비용과 시간이 더 듭니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('car', 'own-damage-coverage', '자기차량손해(자차) — 가입할까 말까', '내 차 수리비를 보장하는 자기차량손해의 보장 범위와 자기부담금, 차량 가치에 따른 가입 판단 기준을 정리했습니다.', '<p>자기차량손해(자차)는 사고로 손상된 내 차의 수리비를 보장하는 담보입니다. 가입은 선택이라, 차량 가치와 운전 환경에 따라 판단합니다.</p>
<h2>보장 범위</h2>
<ul>
<li>충돌·접촉 사고로 인한 내 차 손상</li>
<li>상황에 따라 화재·도난 등(상품·특약에 따라 다름)</li>
</ul>
<h2>자기부담금</h2>
<p>자차는 보통 자기부담금이 있어, 수리비의 일정 비율(최소·최대 한도 내)을 본인이 부담합니다. 자기부담금을 낮추면 보험료가 올라갑니다.</p>
<table>
<thead><tr><th>상황</th><th>자차 권장도</th></tr></thead>
<tbody>
<tr><td>신차·고가 차량</td><td>가입 권장</td></tr>
<tr><td>연식 오래된 저가 차량</td><td>실익 비교 후 선택</td></tr>
</tbody>
</table>
<p>차량 가치가 낮으면 자차 보험료 대비 보장 실익이 줄어, 미가입을 고려할 수 있습니다. 반대로 신차·고가 차량은 가입이 유리합니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>자차=내 차 수리비 보장</li><li>자기부담금 구조 확인</li><li>차량 가치로 가입 실익 판단</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["자동차보험","자차","자기부담금"]', '[{"q":"자차는 의무인가요?","a":"아닙니다. 대인·대물과 달리 선택 담보입니다. 차량 가치와 위험에 따라 결정합니다."},{"q":"자기부담금은 얼마인가요?","a":"보통 수리비의 일정 비율을 최소·최대 한도 내에서 부담합니다. 설정에 따라 보험료가 달라집니다."},{"q":"오래된 차도 자차가 필요한가요?","a":"차량 가치가 낮으면 보험료 대비 실익이 줄어 미가입을 고려할 수 있습니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'policy-analysis-checklist', '보장분석 체크리스트 — 고객 증권 점검하는 법', '설계사가 고객의 기존 보험을 점검할 때 확인해야 할 보장 항목·중복·공백을 체크리스트로 정리했습니다.', '<p>보장분석은 새로운 가입을 권하기 전에 고객의 현재 보장을 정확히 파악하는 과정입니다. 중복은 줄이고 공백은 채우는 것이 목적입니다.</p>
<h2>점검 항목</h2>
<ul>
<li>사망·후유장해: 가족 상황 대비 충분한가</li>
<li>진단비(암·뇌·심장): 핵심 3대 보장 유무</li>
<li>실손·입원·수술: 의료비 보장 공백</li>
<li>갱신 구조: 향후 보험료 인상 가능성</li>
</ul>
<h2>중복과 공백 찾기</h2>
<table>
<thead><tr><th>유형</th><th>대응</th></tr></thead>
<tbody>
<tr><td>중복 보장</td><td>불필요한 특약 정리</td></tr>
<tr><td>보장 공백</td><td>우선순위로 보완</td></tr>
<tr><td>갱신 부담</td><td>비갱신 전환 검토</td></tr>
</tbody>
</table>
<h2>고객에게 설명할 때</h2>
<p>현재 보장을 한눈에 보이는 표로 정리하고, 과장 없이 사실에 근거해 공백을 설명해야 신뢰가 쌓입니다. 무리한 갈아타기 권유는 민원의 원인이 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>3대 진단비·실손·사망 우선 점검</li><li>중복 정리 + 공백 보완</li><li>사실 기반 설명으로 신뢰 형성</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","보장분석","증권분석"]', '[{"q":"보장분석은 무엇부터 보나요?","a":"사망·후유장해, 3대 진단비, 실손·입원·수술 같은 핵심 보장의 유무와 한도를 먼저 확인합니다."},{"q":"기존 보험을 해지하라고 권해도 되나요?","a":"신중해야 합니다. 무리한 갈아타기는 손해와 민원으로 이어질 수 있어 사실에 근거해 비교 설명해야 합니다."},{"q":"중복 보장은 무조건 나쁜가요?","a":"실손처럼 중복 가입해도 비례보상되는 경우가 있어 불필요할 수 있습니다. 보장 성격에 따라 판단합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('whole-life', 'variable-universal-basics', '변액보험·유니버셜 기초 — 이름이 어려운 보험 이해하기', '변액보험과 유니버셜 기능의 개념을 쉽게 풀어 설명하고, 투자·유동성 특징과 가입 시 유의점을 정리했습니다.', '<p>''변액'', ''유니버셜''이 붙은 보험은 이름이 어렵지만, 핵심 개념만 알면 어렵지 않습니다. 둘은 보험에 투자·유동성 기능이 더해진 형태입니다.</p>
<h2>변액보험</h2>
<ul>
<li>보험료 일부를 펀드에 투자해 운용</li>
<li>운용 성과에 따라 적립금·환급금이 달라짐(원금 손실 가능)</li>
</ul>
<h2>유니버셜 기능</h2>
<ul>
<li>납입 유예·추가납입 등 보험료 유연성</li>
<li>일정 조건에서 적립금 중도인출 가능</li>
</ul>
<table>
<thead><tr><th>기능</th><th>장점</th><th>유의</th></tr></thead>
<tbody>
<tr><td>변액(투자)</td><td>장기 수익 기대</td><td>원금 손실·변동성</td></tr>
<tr><td>유니버셜(유동성)</td><td>납입·인출 유연</td><td>인출 시 보장·적립 감소</td></tr>
</tbody>
</table>
<h2>가입 시 유의</h2>
<p>변액은 투자 상품의 성격이 있어 사업비와 변동성을 이해해야 합니다. 단기 자금이나 원금 보장이 목적이라면 적합하지 않을 수 있습니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>변액=투자형(원금 손실 가능)</li><li>유니버셜=납입·인출 유연</li><li>단기·원금보장 목적엔 부적합할 수 있음</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["종신보험","변액보험","유니버셜"]', '[{"q":"변액보험은 원금이 보장되나요?","a":"투자 실적에 따라 적립금이 달라져 원금 손실이 날 수 있습니다. 다만 사망보험금에는 최저보증이 있는 상품도 있습니다."},{"q":"유니버셜이면 아무 때나 돈을 뺄 수 있나요?","a":"일정 조건에서 중도인출이 가능하지만, 인출하면 적립금과 보장에 영향을 줄 수 있습니다."},{"q":"누구에게 적합한가요?","a":"장기 운용과 변동성을 감수할 수 있는 경우에 적합합니다. 단기 자금·원금보장 목적에는 신중해야 합니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('actual-loss', 'manual-therapy-claim-notes', '도수치료 실손 청구 주의점 — 횟수가 많을 때', '도수치료를 실손으로 청구할 때 자주 생기는 추가 자료 요청과 의학적 필요성 쟁점을 정리해 분쟁을 예방합니다.', '<p>도수치료는 실손 청구에서 분쟁이 잦은 항목입니다. 치료 목적이면 보장되지만, 횟수가 많아지면 보험사가 의학적 필요성을 따져 추가 자료를 요청할 수 있습니다.</p>
<h2>왜 자료를 더 요구할까</h2>
<ul>
<li>도수치료는 비급여로 비용·횟수 편차가 큼</li>
<li>치료 목적이 아닌 단순 통증완화·재활 반복은 보장 다툼 발생</li>
</ul>
<h2>준비하면 좋은 자료</h2>
<table>
<thead><tr><th>자료</th><th>역할</th></tr></thead>
<tbody>
<tr><td>진단서·소견서</td><td>진단명과 치료 필요성 입증</td></tr>
<tr><td>치료 경과 기록</td><td>호전 여부·치료 계획 확인</td></tr>
<tr><td>영상검사 결과</td><td>객관적 병변 근거</td></tr>
</tbody>
</table>
<h2>세대·특약 확인</h2>
<p>3·4세대 실손은 도수치료가 비급여 특약으로 분리되어 자기부담·한도(횟수·금액)가 별도로 적용됩니다. 가입한 세대의 조건을 먼저 확인하세요.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>치료 목적·필요성 입증이 핵심</li><li>횟수 많으면 추가 자료 요청 가능</li><li>세대별 비급여 특약 한도 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["실손보험","도수치료","비급여"]', '[{"q":"도수치료는 몇 회까지 보장되나요?","a":"세대·특약의 한도에 따라 다릅니다. 횟수가 많으면 의학적 필요성 자료를 요구받을 수 있습니다."},{"q":"진단명이 없으면 청구가 어렵나요?","a":"치료 목적과 진단을 뒷받침하는 진단서·소견서가 있으면 유리합니다. 단순 통증완화 반복은 다툼이 생길 수 있습니다."},{"q":"4세대도 도수치료가 되나요?","a":"비급여 특약으로 보장되며 자기부담과 횟수·금액 한도가 별도로 적용됩니다."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('claim', 'hospitalization-daily-benefit', '입원일당 청구 — 작지만 챙기면 쏠쏠한 보장', '입원일당(입원급여금)의 개념과 청구 요건, 같은 입원에 대한 중복 청구 가능 여부를 정리했습니다.', '<p>입원일당은 입원 1일당 정해진 금액을 주는 보장입니다. 금액은 작아 보여도 입원이 길어지면 합산액이 커지므로 빠뜨리지 말고 청구하는 것이 좋습니다.</p>
<h2>청구 요건</h2>
<ul>
<li>약관에서 정한 ''입원''에 해당해야 함</li>
<li>입·퇴원확인서로 입원 일수 입증</li>
<li>상품에 따라 면책일수(예: 일정 일수 초과분만 지급)가 있을 수 있음</li>
</ul>
<h2>실손과 별개</h2>
<p>입원일당은 실제 비용과 무관하게 정액으로 지급되므로, 실손의료비와 별개로 함께 받을 수 있습니다. 정액 보장이라 여러 정액 상품에 가입했다면 각각 청구가 가능할 수 있습니다.</p>
<table>
<thead><tr><th>구분</th><th>지급 방식</th></tr></thead>
<tbody>
<tr><td>실손의료비</td><td>실제 비용 비례</td></tr>
<tr><td>입원일당</td><td>일수 × 정액</td></tr>
</tbody>
</table>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>입원일당=일수×정액</li><li>실손과 별개로 청구 가능</li><li>면책일수·입원 정의 확인</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["보험금청구","입원일당","입원급여금"]', '[{"q":"입원일당은 실손이랑 같이 받나요?","a":"네. 정액 보장이라 실제 비용을 보장하는 실손과 별개로 함께 받을 수 있습니다."},{"q":"며칠 입원해야 받나요?","a":"상품에 따라 면책일수가 있어 일정 일수를 초과한 부분만 지급되기도 합니다. 약관을 확인하세요."},{"q":"여러 보험에 입원일당이 있으면요?","a":"정액 보장은 각 계약에서 각각 청구할 수 있는 경우가 많습니다. 약관 기준을 확인하세요."}]', 'published', 'InsureConnect 편집팀');
INSERT OR IGNORE INTO ic_seo_posts (category, slug, title, excerpt, content, tags, faq_json, status, author) VALUES ('practice', 'referral-after-contract', '계약 후 관리와 소개 — 유지율을 높이는 사후관리', '계약 체결 후의 정기 점검과 자연스러운 소개 요청으로 유지율과 신규 고객을 함께 늘리는 사후관리 방법을 정리했습니다.', '<p>보험 영업은 계약이 끝이 아니라 시작입니다. 꾸준한 사후관리는 유지율을 높이고, 자연스러운 소개로 이어져 신규 고객을 만듭니다.</p>
<h2>정기 점검</h2>
<ul>
<li>가입 후 보장 내용·증권 전달 확인</li>
<li>생애 이벤트(결혼·출산·이직) 때 보장 재점검</li>
<li>갱신·납입 변경 시점 안내</li>
</ul>
<h2>소개로 이어가기</h2>
<p>좋은 사후관리 경험이 쌓이면 고객은 자연스럽게 주변을 소개합니다. 무리하게 소개를 요구하기보다, 도움이 되었다는 신뢰가 먼저입니다.</p>
<table>
<thead><tr><th>시점</th><th>활동</th></tr></thead>
<tbody>
<tr><td>가입 직후</td><td>감사·증권 전달·청약철회 안내</td></tr>
<tr><td>정기</td><td>보장 점검·생애 이벤트 대응</td></tr>
<tr><td>청구 시</td><td>청구 지원으로 신뢰 강화</td></tr>
</tbody>
</table>
<p>특히 보험금 청구를 잘 도와준 경험은 강한 신뢰로 남아 소개의 출발점이 됩니다.</p>
<div class="post-key"><strong>핵심 포인트</strong><ul><li>계약 후 정기 점검이 유지율 핵심</li><li>청구 지원이 신뢰를 키움</li><li>신뢰가 쌓이면 소개는 자연스럽게</li></ul></div>
<p class="post-note">본 글은 일반적인 정보 제공을 위한 것으로, 구체적인 보장 여부는 가입하신 상품의 약관과 보험사 안내를 기준으로 합니다. 자세한 내용은 <a href="/disclaimer.html">면책조항</a>을 참고하세요.</p>', '["설계사실무","사후관리","소개"]', '[{"q":"사후관리는 얼마나 자주 하나요?","a":"정기 점검(예: 연 1회)과 생애 이벤트 발생 시 점검을 기본으로 하고, 갱신·납입 변경 시점에 안내합니다."},{"q":"소개를 어떻게 요청하나요?","a":"먼저 도움이 되었다는 신뢰를 쌓는 것이 우선입니다. 무리한 요구보다 자연스러운 만족 경험이 소개로 이어집니다."},{"q":"유지율을 높이는 가장 큰 요인은?","a":"계약 후 꾸준한 점검과 청구 지원입니다. 고객이 관리받고 있다고 느끼면 해지가 줄어듭니다."}]', 'published', 'InsureConnect 편집팀');
